        "sku_id": {
          "type": "string",
          "description": "The unique identifier for the product stock keeping unit."
        }
      },
      "required": [
        "location_id",
        "sku_id"
      ]
    },
    "example_output": {
      "quantity": 15
    }
  },
  "list_location_inventory": {
    "description": "Returns a comprehensive list of all SKUs and their respective quantities currently held at a specific location. Useful for calculating total capacity usage.",
    "parameters": {
      "type": "object",
      "properties": {
        "location_id": {
          "type": "string",
          "description": "The ID of the location to query."
        }
      },
      "required": [
        "location_id"
      ]
    },
    "example_output": {
      "inventory": [
        {
          "sku_id": "sku_001",
          "quantity": 10
        },
        {
          "sku_id": "sku_002",
          "quantity": 50
        }
      ]
    }
  },
  "inspect_location_constraints": {
    "description": "Retrieves metadata and constraints for a specific location, such as maximum storage capacity.",
    "parameters": {
      "type": "object",
      "properties": {
        "location_id": {
          "type": "string",
          "description": "The unique identifier for the location."
        }
      },
      "required": [
