    "description": "Moves a specified quantity of a SKU from a source location to a destination location. Updates inventory levels and logs the transit.",
    "parameters": {
      "type": "object",
      "properties": {
        "from_location_id": {
          "type": "string",
          "description": "The ID of the source location."
        },
        "to_location_id": {
          "type": "string",
          "description": "The ID of the destination location."
        },
        "sku_id": {
          "type": "string",
          "description": "The ID of the SKU to be moved."
        },
        "quantity": {
          "type": "integer",
          "description": "The number of units to transfer."
        }
      },
      "required": [
